	path = strings.TrimSuffix(path, " (deleted)")
	if !strings.Contains(path, ExecuteBeadWtPrefix) {
		return ""
	}
	start := strings.Index(path, ExecuteBeadWtPrefix)
	if start < 0 {
		return ""
	}
	end := start + len(ExecuteBeadWtPrefix)
	for end < len(path) {
		switch path[end] {
