// CleanupStaleAttemptProcesses runs the conservative stale attempt-descendant
// process census and reaping pass without touching temp dirs, evidence, or
// worker sidecars.
func (m *ExecutionCleanupManager) CleanupStaleAttemptProcesses(ctx context.Context) (ExecutionCleanupSummary, error) {
	if m == nil {
		return ExecutionCleanupSummary{}, nil
	}
	summary := ExecutionCleanupSummary{
		ProjectRoot: m.ProjectRoot,
		TempRoot:    m.tempRoot(),
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return summary, err
		}
	}
	if summary.TempRoot == "" {
		summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
	}
	if summary.TempRoot == "" {
		return summary, errors.New("execution cleanup: temp root is empty")
	}
	if m.ProjectRoot == "" {
		return summary, errors.New("execution cleanup: project root is empty")
	}

	now := time.Now
	if m.Now != nil {
		now = m.Now
	}
	probe := m.Probe
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}

	registered := map[string]struct{}{}
	if m.GitOps != nil {
		paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
		if err != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    m.ProjectRoot,
				Class:   "git_worktree_list",
				Message: err.Error(),
			})
		} else {
			for _, p := range paths {
				registered[filepath.Clean(p)] = struct{}{}
			}
		}
	}
	runStates, runStateErr := ReadRunStates(m.ProjectRoot)
	if runStateErr != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Path:    runStateDirPath(m.ProjectRoot),
			Class:   "run_state_read",
			Message: runStateErr.Error(),
		})
	}
	if len(runStates) > 0 || len(registered) > 0 {
		if err := m.cleanupStaleAttemptProcessGroups(ctx, &summary, runStates, registered, probe, now()); err != nil {
			return summary, err
		}
	}
	return summary, nil
}

func (m *ExecutionCleanupManager) cleanupStaleAttemptProcessGroups(
	ctx context.Context,
	summary *ExecutionCleanupSummary,
	runStates []RunState,
	registered map[string]struct{},
	probe ExecutionCleanupLivenessProbe,
	now time.Time,
) error {
	if m == nil || summary == nil {
		return nil
	}
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return err
		}
	}
	scanner := m.attemptProcessScanner
	if scanner == nil {
		scanner = newExecutionCleanupAttemptProcessScanner()
	}
	if scanner == nil {
		return nil
	}
	processes, err := scanner.Scan(ctx)
	if err != nil {
		if errors.Is(err, errExecutionCleanupAttemptProcessUnavailable) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    m.ProjectRoot,
				Class:   "attempt_process_cleanup_unavailable",
				Message: err.Error(),
			})
			summary.ProcessFindings = append(summary.ProcessFindings, ExecutionCleanupProcessFinding{
				StaleReason: err.Error(),
			})
			return nil
		}
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Path:    m.ProjectRoot,
			Class:   "attempt_process_census",
			Message: err.Error(),
		})
		return nil
	}

	for _, group := range groupExecutionCleanupAttemptProcesses(processes) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return err
			}
		}
		finding, stale, err := m.classifyExecutionCleanupAttemptProcessGroup(group.Members, runStates, registered, probe, now, summary)
		if err != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    m.ProjectRoot,
				Class:   "attempt_process_classify",
				Message: err.Error(),
			})
			continue
		}
		if !stale {
			continue
		}
		finding.WouldKill = true
		if !m.DryRun {
			killer := m.attemptProcessKiller
			if killer == nil {
				killer = newExecutionCleanupAttemptProcessKiller()
			}
			if killer != nil {
				if killErr := killer.KillGroup(finding.PGID); killErr != nil {
					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
						Path:    finding.Worktree,
						Class:   "attempt_process_kill",
						Message: killErr.Error(),
					})
					summary.ProcessFindings = append(summary.ProcessFindings, finding)
					continue
				}
			}
			finding.Terminated = true
		}
		summary.ProcessFindings = append(summary.ProcessFindings, finding)
	}
	return nil
}

