		return agent.ExecutionCleanupSummary{}, nil
	}
	mgr := agent.NewExecutionCleanupManager(r.projectRoot, &agent.RealGitOps{})
	mgr.TempRoot = r.tempRoot
	mgr.Now = r.now
	return mgr.CleanupStaleAttemptProcesses(ctx)
}

func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
	if r == nil {
		return agent.ExecutionCleanupSummary{}, nil
	}
	summary := agent.ExecutionCleanupSummary{
		ProjectRoot: r.projectRoot,
		TempRoot:    r.tempRoot,
	}
	if r.processCleanup != nil {
		processSummary, err := r.processCleanup(ctx)
		if err != nil {
			return summary, err
		}
		mergeStartupCleanupSummary(&summary, processSummary)
	}
	report, err := r.scan(ctx, true)
	if err != nil {
		return summary, err
	}
	mergeStartupReport(&summary, report)
	return summary, nil
}

func mergeStartupCleanupSummary(dst *agent.ExecutionCleanupSummary, src agent.ExecutionCleanupSummary) {
	if dst == nil {
		return
	}
	dst.RemovedUnregisteredTempDirs += src.RemovedUnregisteredTempDirs
	dst.RemovedRegisteredWorktrees += src.RemovedRegisteredWorktrees
	dst.RemovedRunStateFiles += src.RemovedRunStateFiles
	dst.RemovedScratchDirs += src.RemovedScratchDirs
	dst.PreservedActiveScratchDirs += src.PreservedActiveScratchDirs
	dst.PrunedCandidateRefs += src.PrunedCandidateRefs
	dst.RemovedEvidenceDirs += src.RemovedEvidenceDirs
	dst.RemovedAgentLogs += src.RemovedAgentLogs
	dst.RemovedWorkerDirs += src.RemovedWorkerDirs
	dst.BytesReclaimed += src.BytesReclaimed
	dst.InodesReclaimed += src.InodesReclaimed
	dst.ScratchBytesReclaimed += src.ScratchBytesReclaimed
	dst.ScratchInodesReclaimed += src.ScratchInodesReclaimed
	dst.Warnings = append(dst.Warnings, src.Warnings...)
	dst.Issues = append(dst.Issues, src.Issues...)
	dst.Observations = append(dst.Observations, src.Observations...)
	dst.ProcessFindings = append(dst.ProcessFindings, src.ProcessFindings...)
}

func mergeStartupReport(dst *agent.ExecutionCleanupSummary, report startupHousekeepingReport) {
	if dst == nil {
		return
	}
	dst.ProjectRoot = report.ProjectRoot
	dst.TempRoot = report.TempRoot
	dst.RemovedRegisteredWorktrees += report.RemovedRegisteredWorktrees
	dst.RemovedUnregisteredTempDirs += report.RemovedUnregisteredTempDirs
	dst.RemovedWorkerDirs += report.RemovedWorkerDirs
	dst.RemovedEvidenceDirs += report.ArchivedExecutionDirs + report.DeletedExecutionDirs
	dst.Warnings = append(dst.Warnings, report.Warnings...)
}

func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
	if r == nil {
		return startupHousekeepingReport{}, nil
	}
	report := startupHousekeepingReport{
		ProjectRoot: r.projectRoot,
		TempRoot:    r.tempRoot,
	}
	if r.projectRoot == "" {
		return report, nil
	}
	now := time.Now().UTC()
	if r.now != nil {
		now = r.now()
	}

	runStates, err := agent.ReadRunStates(r.projectRoot)
	if err != nil {
		return report, err
	}
	if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanWorkerDirs(ctx, now, apply, &report); err != nil {
		return report, err
	}
	if err := r.scanExecutionDirs(ctx, now, runStates, apply, &report); err != nil {
		return report, err
	}
	return report, nil
}

